1	export function scalePixelArt(image: number[][], scaleFactor: number): number[][] {
2	  return image.flatMap(row =>
3	    Array(scaleFactor).fill(row.flatMap(pixel => Array(scaleFactor).fill(pixel)))
4	  );
5	}
